 1	import React from 'react';
 2	import cn from 'classnames';
 3	
 4	import { DataVolumeModelGroupVersionKind } from '@kubevirt-utils/models';
 5	import { NO_DATA_DASH } from '@kubevirt-utils/resources/vm/utils/constants';
 6	import {
 7	  RedExclamationCircleIcon,
 8	  ResourceLink,
 9	  useActiveNamespace,
10	  YellowExclamationTriangleIcon,
11	} from '@openshift-console/dynamic-plugin-sdk';
12	import { ExpandableRowContent, Tbody, Td, Tr } from '@patternfly/react-table';
13	
14	import { NAME_COLUMN_ID } from './hooks/constants';
15	
16	const VirtualMachineDiagnosticTabRow = ({
17	  activeColumns,
18	  dataVolumeResourceLink = false,
19	  expend,
20	  index,
21	  obj,
22	  setExpend,
23	}) => {
24	  const [namespace] = useActiveNamespace();
25	
26	  const isExpanded = expend?.expended.has(obj?.id) && obj?.message;
27	  const activeColumnsObj = new Set<string>(activeColumns.map(({ id }) => id));
28	
29	  return (
30	    <Tbody isExpanded={isExpanded}>
31	      <Tr className={cn({ 'VirtualMachineDiagnosticTabRow--row': isExpanded })}>
32	        <Td
33	          expand={
34	            obj?.message && {
35	              expandId: `message-${index}`,
36	              isExpanded,
37	              onToggle: () =>
38	                setExpend((expendObj) => {
39	                  isExpanded ? expendObj.expended.delete(obj?.id) : expendObj.expended.add(obj?.id);
40	                  return { expended: new Set(expendObj.expended), ids: new Set(expendObj.ids) };
41	                }),
42	              rowIndex: index,
43	            }
44	          }
45	        />
46	        {[...activeColumnsObj]?.map((column) => (
47	          <Td id={column} key={column}>
48	            {column === NAME_COLUMN_ID && dataVolumeResourceLink ? (
49	              <ResourceLink
50	                groupVersionKind={DataVolumeModelGroupVersionKind}
51	                name={obj?.[column]?.toString()}
52	                namespace={namespace}
53	              />
54	            ) : (
55	              obj?.[column]?.toString() || NO_DATA_DASH
56	            )}
57	          </Td>
58	        ))}
59	      </Tr>
60	      {obj?.message && (
61	        <Tr isExpanded={isExpanded}>
62	          <Td colSpan={12}>
63	            <div className="VirtualMachineDiagnosticTabRow--expanded">
64	              {obj?.status === 'False' && <RedExclamationCircleIcon />}
65	              {!obj?.status && <YellowExclamationTriangleIcon />}
66	              <ExpandableRowContent>{obj?.message}</ExpandableRowContent>
67	            </div>
68	          </Td>
69	        </Tr>
70	      )}
71	    </Tbody>
72	  );
73	};
74	
75	export default VirtualMachineDiagnosticTabRow;

